export class TrailColorWeight {
    x;
    y;
    constructor() {
        this.x = 0;
        this.y = 0;
    }
    load(data) {
        if (!data) {
            return;
        }
        if (data.x !== undefined) {
            this.x = data.x;
        }
        if (data.y !== undefined) {
            this.y = data.y;
        }
    }
}
